\begin{lemma}

\leanok
[A contracting homotopy of the identity makes homology vanish]
  \label{lem:isZero_homology_of_homotopy_id_zero}
  \lean{AlgebraicGeometry.isZero_homology_of_homotopy_id_zero}
  Let \(\mathcal{A}\) be a preadditive category and \(D^\bullet\) a cochain complex in
  \(\mathcal{A}\). If there is a homotopy \(\mathrm{id}_{D^\bullet} \simeq 0\) between the
  identity endomorphism of \(D^\bullet\) and the zero endomorphism, then for every degree
  \(p\) the homology object \(H^p(D^\bullet)\) is a zero object.
\end{lemma}
\begin{proof}
  The map induced on homology is a homotopy invariant: homotopic chain maps induce equal
  maps on each homology object. Applying this to the homotopy \(\mathrm{id}_{D^\bullet}
  \simeq 0\), the map induced by \(\mathrm{id}_{D^\bullet}\) on \(H^p(D^\bullet)\) equals the
  map induced by \(0\). The former is \(\mathrm{id}_{H^p(D^\bullet)}\) (homology is a
  functor) and the latter is the zero endomorphism of \(H^p(D^\bullet)\); hence
  \(\mathrm{id}_{H^p(D^\bullet)} = 0\). An object whose identity morphism equals its zero
  endomorphism is a zero object, so \(H^p(D^\bullet)\) is zero.
\end{proof}

\begin{lemma}
[The degree-\(p\) {\v C}ech backbone is the coproduct of intersection opens]
  \label{lem:cech_backbone_left_sigma}
  \lean{AlgebraicGeometry.cechBackbone_left_sigma}
  \uses{def:cover_cech_nerve, def:cech_free_presheaf_complex}
  Let \(\mathcal{U} : X = \bigcup_{i \in I} U_i\) be an open cover with cover arrow
  \(q : \coprod_{i \in I} U_i \to X\), and let \(Y_p\) denote the degree-\(p\) object of the
  {\v C}ech nerve \(\operatorname{coverCechNerveOver}\mathcal{U}\) of
  Definition~\ref{def:cover_cech_nerve} --- the \((p+1)\)-fold fibre power of \(q\) over
  \(X\). Then \(Y_p\) is canonically the coproduct
  \[
    Y_p \;\cong\; \coprod_{\sigma : \mathrm{Fin}(p+1) \to I} U_\sigma,
    \qquad
    U_\sigma \;=\; \operatorname{coverInterOpen}\mathcal{U}\,\sigma \;=\;
      \bigcap_{k} U_{\sigma(k)},
  \]
  indexed by the multi-indices \(\sigma\), and the structure map \(q_p : Y_p \to X\) is
  \(\operatorname{Sigma.desc}(\sigma \mapsto j_\sigma)\), where
  \(j_\sigma : U_\sigma \hookrightarrow X\) is the open immersion of the intersection open
  \(U_\sigma\) of Definition~\ref{def:cech_free_presheaf_complex}. In words: the fibre power
  of the open immersions \(U_i \hookrightarrow X\) is the intersection open, and the disjoint
  union over \(\sigma\) assembles the {\v C}ech backbone.
\end{lemma}
\begin{proof}
  \uses{def:cover_cech_nerve, def:cech_free_presheaf_complex}
  The coproduct \(\coprod_i U_i\) has, in degree \(p\), the \((p+1)\)-fold fibre power over
  \(X\); fibre products distribute over coproducts, so \(\bigl(\coprod_i U_i\bigr)^{\times_X
  (p+1)} \cong \coprod_{\sigma : \mathrm{Fin}(p+1) \to I} U_{\sigma(0)} \times_X \cdots
  \times_X U_{\sigma(p)}\). Each factor \(U_{\sigma(k)} \hookrightarrow X\) is an open
  immersion, and the fibre product of open immersions over \(X\) is the intersection of
  their images, so \(U_{\sigma(0)} \times_X \cdots \times_X U_{\sigma(p)} \cong \bigcap_k
  U_{\sigma(k)} = U_\sigma\). Under this identification the structure map of the
  \(\sigma\)-component is the open immersion \(j_\sigma\), and the universal map out of the
  coproduct is \(\operatorname{Sigma.desc}(\sigma \mapsto j_\sigma)\).
\end{proof}

\begin{lemma}
[Push--pull over the {\v C}ech backbone is the product over intersection opens]
  \label{lem:pushPull_sigma_iso}
  \lean{AlgebraicGeometry.pushPull_sigma_iso}
  \uses{def:push_pull_obj, lem:cech_backbone_left_sigma, lem:coprodPresheafObjIso_mathlib,
    lem:isProductOfDisjoint_mathlib}
  With the notation of Lemma~\ref{lem:cech_backbone_left_sigma}, the push--pull object on
  the degree-\(p\) backbone decomposes as a product over the multi-indices:
  \[
    \operatorname{pushPullObj}\mathcal{F}\,Y_p
      \;\cong\;
    \prod_{\sigma : \mathrm{Fin}(p+1) \to I}
      \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk} j_\sigma)
    \qquad \text{in } X.\mathrm{Modules},
  \]
  equivalently \((q_p)_*\,(q_p)^*\mathcal{F} \cong \prod_\sigma (j_\sigma)_*\,
  (j_\sigma)^*\mathcal{F}\).
\end{lemma}
\begin{proof}
  \uses{lem:cech_backbone_left_sigma, lem:coprodPresheafObjIso_mathlib,
    lem:isProductOfDisjoint_mathlib}
  By Lemma~\ref{lem:cech_backbone_left_sigma} the backbone \(Y_p\) is the coproduct
  \(\coprod_\sigma U_\sigma\) with structure map \(q_p = \operatorname{Sigma.desc}(\sigma
  \mapsto j_\sigma)\). A sheaf of modules on a coproduct scheme is the product of its
  restrictions to the components: although the images \(U_\sigma \subseteq X\) overlap, the
  components are \emph{disjoint inside the coproduct space} \(\coprod_\sigma U_\sigma\), so
  the sheaf condition over the disjoint cover by the components expresses the sections over
  any open as the product of the sections over the component traces. Pulling \(\mathcal{F}\)
  back along \(q_p\) and pushing forward therefore yields, componentwise, the push--pull of
  \(\mathcal{F}\) along each \(j_\sigma\).

  Concretely, build the module-linear comparison map \(\operatorname{pushPullObj}\mathcal{F}\,
  Y_p \to \prod_\sigma \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk}
  j_\sigma)\) from the projections induced by the coproduct inclusions \(U_\sigma
  \hookrightarrow Y_p\). To check it is an isomorphism it suffices, since the forgetful
  functor \(\operatorname{Scheme.Modules.toPresheaf}\) is faithful, reflects isomorphisms,
  and preserves limits, to verify the statement on the underlying presheaf of abelian
  groups. There the comparison is the indexed disjoint-union sheaf decomposition: the binary
  case is \(\operatorname{coprodPresheafObjIso}\) of
  Lemma~\ref{lem:coprodPresheafObjIso_mathlib} (sections over a binary coproduct scheme are
  the product of the sections over the two preimages) and, for an abstract sheaf on a space,
  \(\operatorname{isProductOfDisjoint}\) of Lemma~\ref{lem:isProductOfDisjoint_mathlib} (for
  \(U \sqcap V = \bot\), \(F(U \sqcup V) \cong F(U) \times F(V)\)); iterating the binary
  decomposition over the finite index set \(\{\sigma\}\) gives the indexed product.
  Transporting the resulting presheaf isomorphism back through
  \(\operatorname{toPresheaf}\) shows the module-linear comparison is an isomorphism.
\end{proof}

\begin{lemma}
[Sections of one push--pull leg over an open]
  \label{lem:pushPull_leg_sections}
  \lean{AlgebraicGeometry.pushPull_leg_sections}
  \uses{def:push_pull_obj, def:cech_free_presheaf_complex, lem:pushforward_obj_obj_mathlib,
    lem:restrictFunctorIsoPullback_mathlib, lem:restrict_obj_mathlib}
  Let \(j_\sigma : U_\sigma \hookrightarrow X\) be the open immersion of the intersection
  open \(U_\sigma = \operatorname{coverInterOpen}\mathcal{U}\,\sigma\), and let
  \(V \subseteq X\) be an open. Then there is a natural isomorphism of section groups
  \[
    \Gamma\bigl(V,\, \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk}
      j_\sigma)\bigr)
      \;\cong\;
    \Gamma\bigl(U_\sigma \cap V,\, \mathcal{F}\bigr).
  \]
\end{lemma}
\begin{proof}
  \uses{lem:pushforward_obj_obj_mathlib, lem:restrictFunctorIsoPullback_mathlib,
    lem:restrict_obj_mathlib}
  This follows from three standard identifications. First, the leg is
  \((j_\sigma)_*\,(j_\sigma)^*\mathcal{F}\); pushforward sections are computed by preimage,
  \(\Gamma\bigl(V, (j_\sigma)_* N\bigr) = \Gamma\bigl(j_\sigma^{-1}(V), N\bigr)\)
  (Lemma~\ref{lem:pushforward_obj_obj_mathlib}, an equality), applied with \(N =
  (j_\sigma)^*\mathcal{F}\). Second, pullback along the open immersion \(j_\sigma\) is the
  restriction functor: \((j_\sigma)^*\mathcal{F} \cong \mathcal{F}.\operatorname{restrict}
  j_\sigma\) by Lemma~\ref{lem:restrictFunctorIsoPullback_mathlib}. Third, the sections of a
  restricted module over \(j_\sigma^{-1}(V)\) are the sections of \(\mathcal{F}\) over the
  image open (Lemma~\ref{lem:restrict_obj_mathlib}, an equality): \(\Gamma\bigl(j_\sigma^{-1}
  (V), \mathcal{F}.\operatorname{restrict} j_\sigma\bigr) = \Gamma\bigl(j_\sigma\bigl(
  j_\sigma^{-1}(V)\bigr), \mathcal{F}\bigr) = \Gamma\bigl(U_\sigma \cap V, \mathcal{F}\bigr)\),
  the last equality because the image of the preimage of \(V\) under the open immersion
  \(j_\sigma : U_\sigma \hookrightarrow X\) is exactly \(U_\sigma \cap V\). Composing the
  three gives the stated isomorphism.
\end{proof}

\begin{lemma}
[Degreewise section identification of the {\v C}ech backbone]
  \label{lem:pushPull_eval_prod_iso}
  \lean{AlgebraicGeometry.pushPull_eval_prod_iso}
  \uses{lem:pushPull_sigma_iso, lem:pushPull_leg_sections,
    lem:evaluation_preserves_products_mathlib}
  For an open \(V \subseteq X\) and every degree \(p\) there is an isomorphism
  \[
    \Gamma\bigl(V,\, \operatorname{pushPullObj}\mathcal{F}\,Y_p\bigr)
      \;\cong\;
    \prod_{\sigma : \mathrm{Fin}(p+1) \to I}
      \Gamma\bigl(\operatorname{coverInterOpen}\mathcal{U}\,\sigma \cap V,\, \mathcal{F}\bigr).
  \]
\end{lemma}
\begin{proof}
  \uses{lem:pushPull_sigma_iso, lem:pushPull_leg_sections,
    lem:evaluation_preserves_products_mathlib}
  Combine the product decomposition of the backbone push--pull object
  (Lemma~\ref{lem:pushPull_sigma_iso}), \(\operatorname{pushPullObj}\mathcal{F}\,Y_p \cong
  \prod_\sigma \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk} j_\sigma)\),
  with the fact that the section (evaluation-at-\(V\)) functor on \(X.\mathrm{Modules}\)
  preserves products (Lemma~\ref{lem:evaluation_preserves_products_mathlib}): \(\Gamma(V,
  \prod_\sigma N_\sigma) \cong \prod_\sigma \Gamma(V, N_\sigma)\). This reduces the
  left-hand side to \(\prod_\sigma \Gamma\bigl(V, \operatorname{pushPullObj}\mathcal{F}\,
  (\operatorname{Over.mk} j_\sigma)\bigr)\), and the per-leg section identification
  (Lemma~\ref{lem:pushPull_leg_sections}) rewrites each factor as \(\Gamma(U_\sigma \cap V,
  \mathcal{F})\).
\end{proof}

\begin{lemma}
[The evaluated augmented {\v C}ech complex is the concrete section {\v C}ech complex]
  \label{lem:cechSection_complex_iso}
  \lean{AlgebraicGeometry.cechSection_complex_iso}
  \uses{lem:pushPull_eval_prod_iso, lem:section_cech_objd_apply,
    lem:section_cech_product_equiv, def:cech_augmented_complex}
  Fix an open \(V \subseteq X\). The augmented {\v C}ech complex of
  Definition~\ref{def:cech_augmented_complex} evaluated at \(V\) (through
  \(\operatorname{toPresheaf}\)) --- call it \(D^\bullet\), the cochain complex of abelian
  groups with \(D^p = \Gamma(V, \operatorname{pushPullObj}\mathcal{F}\,Y_p)\) --- is
  isomorphic, as a cochain complex, to the concrete section {\v C}ech complex \(D'^\bullet\)
  over the family \(\bigl(\operatorname{coverInterOpen}\mathcal{U}\,\cdot \cap V\bigr)\): the
  complex with \(D'^p = \prod_\sigma \Gamma(U_\sigma \cap V, \mathcal{F})\) and the
  alternating coface restriction differential. The isomorphism is the degreewise map of
  Lemma~\ref{lem:pushPull_eval_prod_iso}, and it intertwines the two differentials.
\end{lemma}
\begin{proof}
  \uses{lem:pushPull_eval_prod_iso, lem:section_cech_objd_apply,
    lem:section_cech_product_equiv}
  In each degree \(p\) the object isomorphism \(D^p \cong D'^p\) is
  Lemma~\ref{lem:pushPull_eval_prod_iso}. It remains to check the degreewise isomorphisms
  commute with the differentials. The differential of \(D'^\bullet\) is, read through the
  product equivalence \(\operatorname{sectionCechProductEquiv}\)
  (Lemma~\ref{lem:section_cech_product_equiv}), the alternating sum of presheaf face
  restrictions \(\sum_i (-1)^i\, \operatorname{sectionCechFaceRestr}(\sigma, i)\) computed in
  Lemma~\ref{lem:section_cech_objd_apply}. The differential of \(D^\bullet\) is the
  evaluation at \(V\) of the {\v C}ech-nerve coface maps, assembled from the same push--pull
  restriction comparisons; under the degreewise identification each coface of \(D^\bullet\)
  becomes the corresponding face restriction of \(D'^\bullet\), so the alternating sums
  agree. Reusing the alternating-sum bookkeeping of Lemma~\ref{lem:section_cech_objd_apply}
  --- rather than rebuilding it --- matches the differentials and yields the isomorphism of
  complexes.
\end{proof}

\begin{lemma}
[The section {\v C}ech complex inside a cover member is contractible]
  \label{lem:cechSection_contractible}
  \lean{AlgebraicGeometry.cechSection_contractible}
  \uses{lem:cechSection_complex_iso, lem:cech_acyclic_affine, lem:cech_engine_complex,
    def:cech_free_presheaf_complex}
  Suppose \(V \le \operatorname{coverOpen}\mathcal{U}\,i_{\mathrm{fix}}\) for some fixed index
  \(i_{\mathrm{fix}}\), i.e.\ \(V\) lies inside one cover member. Then the concrete section
  {\v C}ech complex \(D'^\bullet\) of Lemma~\ref{lem:cechSection_complex_iso} over the family
  \(U'_j = \operatorname{coverInterOpen}\mathcal{U}\,j \cap V\) admits a contracting homotopy
  \(\mathrm{id}_{D'^\bullet} \simeq 0\).
\end{lemma}
\begin{proof}
  \uses{lem:cech_acyclic_affine, lem:cech_engine_complex}
  Because \(V \le U_{i_{\mathrm{fix}}}\), the restricted family \(U'_j = U_j \cap V\) has a
  \emph{maximum}: \(U'_{i_{\mathrm{fix}}} = U_{i_{\mathrm{fix}}} \cap V = V\), and every
  \(U'_j \le V\). Consequently, for each multi-index \(\sigma\),
  \(U'_{i_{\mathrm{fix}}\,\sigma} = U_{i_{\mathrm{fix}}} \cap U_\sigma \cap V = U_\sigma \cap
  V = U'_\sigma\): prepending the index \(i_{\mathrm{fix}}\) does not change the open, so the
  prepend map is the \emph{identity} on each coefficient \(\Gamma(U'_\sigma, \mathcal{F})\)
  (the membership criterion \(\operatorname{le\_coverInterOpen\_iff}\) of
  Lemma~\ref{lem:cech_engine_complex}). The dependent-coefficient combinatorial {\v C}ech
  engine --- \(\operatorname{depDiff}\), \(\operatorname{depHomotopy}\),
  \(\operatorname{depHomotopy\_spec}\), \(\operatorname{depDiff\_exact}\) of
  Lemma~\ref{lem:cech_acyclic_affine} --- then supplies the prepend-\(i_{\mathrm{fix}}\)
  contracting homotopy \(h\) with \(d \circ h + h \circ d = \mathrm{id}\), since its unit,
  shift, and coface-commutation compatibilities all hold with the prepend map acting as the
  identity. Packaging \(h\) as a homotopy of cochain complexes gives \(\mathrm{id}_{D'^\bullet}
  \simeq 0\).
\end{proof}

\begin{lemma}
[Local vanishing of the evaluated augmented {\v C}ech homology]
  \label{lem:cechSection_isZero_homology}
  \lean{AlgebraicGeometry.cechSection_isZero_homology}
  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
    lem:isZero_homology_of_homotopy_id_zero}
  Let \(V \le \operatorname{coverOpen}\mathcal{U}\,i\) for some index \(i\). Then for every
  degree \(p\) the homology \(H^p(D^\bullet)\) of the augmented {\v C}ech complex evaluated at
  \(V\) (the complex \(D^\bullet\) of Lemma~\ref{lem:cechSection_complex_iso}) is a zero
  object; equivalently \(D^\bullet\) carries a contracting homotopy \(\mathrm{id}_{D^\bullet}
  \simeq 0\). This is the residual obligation of Step~3 of
  Lemma~\ref{lem:cech_augmented_resolution}.
\end{lemma}
\begin{proof}
  \uses{lem:cechSection_complex_iso, lem:cechSection_contractible,
    lem:isZero_homology_of_homotopy_id_zero}
  By Lemma~\ref{lem:cechSection_complex_iso} the evaluated complex \(D^\bullet\) is
  isomorphic to the concrete section {\v C}ech complex \(D'^\bullet\). The hypothesis \(V \le
  \operatorname{coverOpen}\mathcal{U}\,i\) places \(V\) inside one cover member, so
  Lemma~\ref{lem:cechSection_contractible} gives a contracting homotopy \(\mathrm{id}_{D'^\bullet}
  \simeq 0\); transporting it across the complex isomorphism yields \(\mathrm{id}_{D^\bullet}
  \simeq 0\). Lemma~\ref{lem:isZero_homology_of_homotopy_id_zero} then makes
  \(H^p(D^\bullet)\) a zero object in every degree.
\end{proof}

